package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithSkipHeaderRecord_noArg_returnsInstanceWithSkipHeaderRecordTrue() {
        CSVFormat original = CSVFormat.DEFAULT;
        CSVFormat updated = original.withSkipHeaderRecord();
        assertNotNull(updated);
        assertTrue(updated.getSkipHeaderRecord());
        // Original instance should remain unchanged (immutable)
        assertFalse(original.getSkipHeaderRecord());
    }
}
